<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gradlew.bat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # Windows</span></span>
